import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './PropertyPage.css';

const API_URL = 'http://localhost:5000/api';

function PropertyPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [property, setProperty] = useState(null);
  const [media, setMedia] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentMediaIndex, setCurrentMediaIndex] = useState(0);

  useEffect(() => {
    fetchProperty();
    fetchMedia();
  }, [id]);

  const fetchProperty = async () => {
    try {
      const response = await axios.get(`${API_URL}/properties/${id}`);
      setProperty(response.data);
    } catch (error) {
      console.error('Error fetching property:', error);
      navigate('/catalog');
    }
  };

  const fetchMedia = async () => {
    try {
      const response = await axios.get(`${API_URL}/upload/${id}`);
      setMedia(response.data);
    } catch (error) {
      console.error('Error fetching media:', error);
    } finally {
      setLoading(false);
    }
  };

  const nextMedia = () => {
    if (currentMediaIndex < media.length - 1) {
      setCurrentMediaIndex(currentMediaIndex + 1);
    }
  };

  const prevMedia = () => {
    if (currentMediaIndex > 0) {
      setCurrentMediaIndex(currentMediaIndex - 1);
    }
  };

  const handleContact = () => {
    if (property?.owner_email) {
      window.location.href = `mailto:${property.owner_email}`;
    }
  };

  if (loading) return <div className="loading">Загрузка...</div>;
  if (!property) return <div className="loading">Объект не найден</div>;

  return (
    <div className="property-page">
      <div className="property-gallery">
        {media.length > 0 ? (
          <>
            <div className="gallery-container">
              {media[currentMediaIndex].file_type === 'photo' ? (
                <img 
                  src={`http://localhost:5000${media[currentMediaIndex].file_url}`} 
                  alt={property.title}
                />
              ) : (
                <video 
                  src={`http://localhost:5001${media[currentMediaIndex].file_url}`} 
                  controls
                  style={{ width: '100%' }}
                />
              )}
              
              {media.length > 1 && (
                <>
                  <button onClick={prevMedia} className="gallery-nav prev" disabled={currentMediaIndex === 0}>
                    ‹
                  </button>
                  <button onClick={nextMedia} className="gallery-nav next" disabled={currentMediaIndex === media.length - 1}>
                    ›
                  </button>
                </>
              )}
            </div>
            
            <div className="gallery-thumbs">
              {media.map((item, index) => (
                <div 
                  key={item.id} 
                  className={`thumb ${index === currentMediaIndex ? 'active' : ''}`}
                  onClick={() => setCurrentMediaIndex(index)}
                >
                  {item.file_type === 'photo' ? (
                    <img src={`http://localhost:5001${item.file_url}`} alt={`Thumb ${index}`} />
                  ) : (
                    <div className="video-thumb">🎥</div>
                  )}
                </div>
              ))}
            </div>
          </>
        ) : (
          <img 
            src={property.image || 'https://via.placeholder.com/800x500?text=Недвижимость'} 
            alt={property.title} 
          />
        )}
      </div>

      <div className="property-info">
        <h1>{property.title}</h1>
        <div className="property-price">{Number(property.price).toLocaleString()} ₽</div>
        
        <div className="property-details">
          <div className="detail-item">
            <span className="detail-label">Спальни:</span>
            <span>{property.rooms || '-'}</span>
          </div>
          <div className="detail-item">
            <span className="detail-label">Ванные комнаты:</span>
            <span>{property.bathrooms || '-'}</span>
          </div>
          <div className="detail-item">
            <span className="detail-label">Кв. м.:</span>
            <span>{property.area || '-'}</span>
          </div>
          <div className="detail-item">
            <span className="detail-label">Год постройки:</span>
            <span>{property.year || '-'}</span>
          </div>
        </div>

        <div className="property-description">
          <h3>Описание объекта</h3>
          <p>{property.description || 'Нет описания'}</p>
        </div>

        <div className="property-location">
          <h3>Месторасположение на карте</h3>
          <p>{property.city}, {property.address || 'Адрес не указан'}</p>
        </div>

        <div className="property-contacts">
          <h3>Контакты</h3>
          <p>📞 {property.owner_phone || 'Не указан'}</p>
          <p>✉️ {property.owner_email || 'Не указан'}</p>
          <button onClick={handleContact} className="contact-btn">
            Связаться с продавцом
          </button>
        </div>
      </div>
    </div>
  );
}

export default PropertyPage;
